#include <stdio.h>
int main(){
    int n; if(scanf("%d",&n)!=1) return 0;
    char s[101]; scanf("%s",s);
    int cnt=0;
    for(int i=0;i<n;i++){
        char c=s[i];
        if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt++;
    }
    printf("%d\n",cnt);
    return 0;
}

